INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000031', E'플리마켓 디피 꿀팁 공유해요', E'디피할 때 높낮이 차이를 주면 시선이 잘 가요. 우드 박스로 단 만들고, 린넨 천 깔고, LED 스트링라이트 달면 분위기 확 달라져요!', '자유게시판', 'seller', E'류서연', false, 34, NOW() - interval '24 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000069', E'거스름돈 얼마나 준비하세요?', E'다음 주 첫 플리마켓인데 거스름돈 준비가 고민이에요. 천원짜리 30장, 오천원짜리 10장이면 될까요?', '자유게시판', 'seller', E'윤소윤', false, 12, NOW() - interval '11 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000043', E'카드 결제 단말기 추천', E'토스, 페이코, 키오스크 뭐가 좋을까요? 수수료도 비교해보고 싶어요.', '자유게시판', 'seller', E'조건우', false, 1, NOW() - interval '19 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000064', E'혼자 플리마켓 참가하시는 분?', E'화장실 갈 때가 제일 곤란해요. 옆 부스 셀러분께 부탁하거나 잠깐 비우는데... 팁 있으신가요?', '자유게시판', 'seller', E'황민준', false, 50, NOW() - interval '27 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000089', E'여름 야외 마켓 생존 키트', E'선크림, 미니 선풍기, 얼음물 텀블러, 양산, 쿨타올, 모기 퇴치 스프레이. 이것만 해도 생존 가능!', '자유게시판', 'foodtruck', E'안서연', false, 6, NOW() - interval '5 days');
